const geminiResponse = $input.item.json; // Resposta do HTTP Request
const dadosOriginais = $input.last().json; // Dados que entraram no HTTP (do loop)

// === EXTRAI E LIMPA O JSON ===
const rawText = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
const cleanText = rawText.replace(/```json|```/g, '').trim();

// === PARSE SEGURO ===
let classificacao;
try {
  classificacao = JSON.parse(cleanText);

  // Valida se tem os campos obrigatórios
  if (!classificacao.tipo || !classificacao.formato) {
    throw new Error('Classificação incompleta');
  }

} catch (error) {
  console.error('❌ Erro ao processar classificação:', error.message);
  console.error('📄 Resposta recebida:', rawText);

  // Classificação de fallback
  classificacao = {
    tipo: 'DESCONHECIDO',
    formato: 'PDF_ESTRUTURADO',
    confianca: 0,
    indicadoresEncontrados: [],
    observacao: `Erro: ${error.message}`,
    cnpjDetectado: null,
    periodoDetectado: null
  };
}

// === MAPEIA STATUS PARA FACILITAR FILTROS ===
const statusMap = {
  'PGDAS_PDF': 'pgdas',
  'PGDAS_XML': 'pgdas',
  'EXTRATO_BANCARIO': 'extrato_financeiro',
  'EXTRATO_CARTAO': 'extrato_financeiro',
  'FOLHA_PAGAMENTO': 'folha',
  'NFSE_PDF': 'nota_fiscal',
  'NFSE_XML': 'nota_fiscal',
  'NFE_XML': 'nota_fiscal',
  'CTE_XML': 'nota_fiscal',
  'RELATORIO_VENDAS': 'outros',
  'DESCONHECIDO': 'desconhecido'
};

// === VALIDA CONFIANÇA ===
const confiancaMinima = 0.7;
const precisaRevisao = classificacao.confianca < confiancaMinima;

// === RETORNA ESTRUTURA PADRONIZADA ===
return {
  // === IDENTIFICAÇÃO ===
  reportId: dadosOriginais.reportId,
  documentoIndex: dadosOriginais.documentoIndex,
  documentoNome: dadosOriginais.documentoNome,

  // === DADOS DO CLIENTE ===
  clienteId: dadosOriginais.clienteId,
  clienteNome: dadosOriginais.clienteNome,
  regimeTributario: dadosOriginais.regimeTributario,

  // === ARQUIVO GEMINI ===
  file_uri: dadosOriginais.file_uri,
  mime_type: dadosOriginais.mime_type,
  state: dadosOriginais.state,

  // === CLASSIFICAÇÃO ===
  tipo: classificacao.tipo,
  tipoCategoria: statusMap[classificacao.tipo] || 'desconhecido',
  formato: classificacao.formato,
  confianca: classificacao.confianca,
  precisaRevisao: precisaRevisao,

  // === METADADOS EXTRAÍDOS ===
  indicadoresEncontrados: classificacao.indicadoresEncontrados || [],
  observacao: classificacao.observacao || '',
  cnpjDetectado: classificacao.cnpjDetectado || null,
  periodoDetectado: classificacao.periodoDetectado || null,

  // === CONTROLE ===
  totalDocumentos: dadosOriginais.totalDocumentos,
  timestamp: new Date().toISOString(),

  // === DEBUG (opcional - remova em produção) ===
  _debug: {
    respostaOriginal: rawText,
    classificacaoCompleta: classificacao
  }
};
